var dle_theme = '';
var file_uploaders = [];


function getBaseSize () {
	const BaseElement = document.querySelector("html");
	const BaseSize = parseFloat(window.getComputedStyle(BaseElement).getPropertyValue("font-size"));

	return BaseSize / 16;
}

function setDarkMode () {

	var night_time = {
	  '0'  : {'from' : 16.2, 'to' : 8.4 },
	  '1'  : {'from' : 17.3, 'to' : 7.5 },
	  '2'  : {'from' : 18.3, 'to' : 6.4 },
	  '3'  : {'from' : 19.3, 'to' : 5.3 },
	  '4'  : {'from' : 20.3, 'to' : 4.2 },
	  '5'  : {'from' : 21.2, 'to' : 3.5 },
	  '6'  : {'from' : 21, 'to' : 4 },
	  '7'  : {'from' : 20, 'to' : 5 },
	  '8'  : {'from' : 18.5, 'to' : 6 },
	  '9'  : {'from' : 17.3, 'to' : 7 },
	  '10'  : {'from' : 16.2, 'to' : 8 },
	  '11'  : {'from' : 16, 'to' : 8.5 }
	};

	var date = new Date();

	var m = date.getMonth();
	var minutes = date.getMinutes();

	if( minutes < 10 ) { minutes = '0'+ minutes; }
	var h = parseFloat(date.getHours() + '.' + minutes);

	if( h >= night_time[m].from || h <= night_time[m].to || (window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches) ) {

		$('.sidebar').removeClass('sidebar-default');
		document.body.className = document.body.className.replace(/dle_theme_/g, 'saved_dle_theme_');
		$('body').addClass('dle_theme_dark');
		$('body').addClass('auto_night_mode');

		dle_theme = 'dle_theme_dark';

		if (typeof init_dle_editor === "function") {
			init_dle_editor ( 'textarea.wysiwygeditor' );
		}

	}

}

function reload () {
	
	var rndval = new Date().getTime(); 
	
	document.getElementById('dle-captcha').innerHTML = '<img src="index.php?controller=antibot&rndval=' + rndval + '" style="width: 130px;height: 46px;" alt="" />';
	
};

function Help(section) {

		if(section == "social") {

			var ww = 830 * getBaseSize();

		} else {
			var ww = 570 * getBaseSize();
		}

		var wh = 550 * getBaseSize();

		if(ww > ( $(window).width() * 0.95 ) )  { ww = $(window).width() * 0.95;  }
		if(wh > ( $(window).height() * 0.95 ) ) { wh = $(window).height() * 0.95; }

		ShowLoading();

		$.get("?mod=help&section=", { section: section }, function(data){

			HideLoading();

			$("#panel-help-section").remove();

			$("body").append(data);

			$('#panel-help-section').dialog({
				autoOpen: true,
				width: ww,
				height: wh,
				resizable: false,
				buttons: {
					"OK": function() { 
						$(this).dialog("close");
						$("#panel-help-section").remove();							
					}
				}
			});

		});

		return false;


}

function ShowOrHide(d1, d2) {
	if (d2) { 

		DoDiv(d1); 
		DoDiv(d2); 

	} else {

		var item = $("#" + d1);
		if (item.is(":hidden")) { 
			item.show('blind',{},1000);
		} else {
			item.hide('blind',{},1000);
		}

	}
}

function DoDiv(id) {

	if ( $("#" + id).is(":hidden") ) {

		$("#" + id).show(1);

	} else {

		$("#" + id).hide(1);
	}
}

function ShowLoading( message, positionx,  positiony) {

	var classname = '';

	if (typeof positionx == 'undefined') {
		var positionx = 'center';
	}

	if (typeof positiony == 'undefined') {
		var positiony = 'center';
	}

	if (typeof message == 'undefined') {
		var message = '';
	}

	$('#loading-layer').remove();

	if ( message.length === 0 || !message.trim() ) {
		message = '<div class="loading"></div>';
		classname ='withouttext';
	} else {
		classname ='withtext';
		message = '<span>' + message + '</span>';
	}

	$('body').append('<div id="loading-layer" class="' + classname + '" style="display:none">' + message + '</div>');

	var setX = ($(window).width() / 2) - ($("#loading-layer").outerWidth() / 2);
	var setY = ($(window).height() / 2) - ($("#loading-layer").outerHeight() / 2) - 50;

	switch (positionx) {
	  case 'left':
	    setX = 40;
	    break;
	  case 'right':
	    setX = ( $(window).width()  - $("#loading-layer").outerWidth()  ) - 40;
	    break;
	}

	switch (positiony) {
	  case 'top':
	    setY = 40;
	    break;
	  case 'bottom':
	    setY = ( $(window).height() - $("#loading-layer").outerHeight() ) - 40;
	    break;
	}

	$("#loading-layer").css( {
		left : setX + "px",
		top : setY + "px",
		position : 'fixed',
		zIndex : '99999'
	});
		
	$("#loading-layer").show();

};

function HideLoading( message ) {
	$("#loading-layer").hide();
};

function DLEalert(message, title) {

	if($("#dlepopup").length){
		$("#dlepopup").dialog("close");
		$("#dlepopup").remove();
	}

	$("body").append("<div id='dlepopup' class='dle-alert' title='" + title + "' style='display:none'>"+ message +"</div>");

	var ww = 500 * getBaseSize();

	if(ww > ( $(window).width() * 0.95 ) )  { ww = $(window).width() * 0.95;  }

	$('#dlepopup').dialog({
		autoOpen: true,
		width: ww,
		minHeight: 160,
		resizable: false,
		buttons: {
			"Ok": function() { 
				$(this).dialog("close");
				$("#dlepopup").remove();							
			}
		}
	});
};

