function DLEprompt(message, d, title, callback, allowempty, savebutton) {

	var b = {};
	
	if (typeof savebutton == 'undefined') {
		var savebutton = dle_act_lang[2];
	}

	b[dle_act_lang[3]] = function() { 
					$(this).dialog("close");						
			    };

	b[savebutton] = function() { 
					if ( !allowempty && $("#dle-promt-text").val().length < 1) {
						 $("#dle-promt-text").addClass('ui-state-error');
					} else {
						var response = $("#dle-promt-text").val()
						$(this).dialog("close");
						$("#dlepopup").remove();
						if( callback ) callback( response );	
					}				
				};

	var ww = 500 * getBaseSize();

	if(ww > ( $(window).width() * 0.95 ) )  { ww = $(window).width() * 0.95;  }

	if($("#dlepopup").length){
		$("#dlepopup").dialog("close");
		$("#dlepopup").remove();
	}

	$("body").append("<div id='dlepopup' class='dle-promt' title='" + title + "' style='display:none'>"+ message +"<br><input type='text' dir='auto' name='dle-promt-text' id='dle-promt-text' class='form-control' style='width:100%;' value=\"" + d + "\"></div>");

	$('#dlepopup').dialog({
		autoOpen: true,
		width: ww,
		resizable: false,
		buttons: b
	});

	if (d.length > 0) {
		$("#dle-promt-text").select().focus();
	} else {
		$("#dle-promt-text").focus();
	}
};

jQuery.getCachedScript = function( url, options ) {
 
  options = $.extend( options || {}, {
    dataType: "script",
    cache: true,
    url: url
  });
 
  return jQuery.ajax( options );
};

var media_upload_manager = false;

function media_upload ( area, author, news_id, wysiwyg) {

		var manager = area+author+news_id+wysiwyg;

		if ($("#mediaupload").hasClass('ui-dialog-content') && media_upload_manager == manager ) {
			$('#mediaupload').dialog('open');
			check_all();
			return false;
		}

		if($("#mediaupload").length){
			$("#mediaupload").dialog("close");
			$('#mediaupload').remove();
		}

		$('body').append("<div id='mediaupload' class='mediaupload-body' title='"+dle_act_lang[4]+"' style='display:none'></div>");

		ShowLoading();

		$.get("index.php?controller=ajax", { mod: 'upload', area: area, news_id: news_id, author: author, wysiwyg: wysiwyg }, function(data){

			HideLoading();

			$("#mediaupload").html(data);

			var ww = 900 * getBaseSize();
			var wh = 600 * getBaseSize();

			if(ww > ( $(window).width() * 0.95 ) )  { ww = $(window).width() * 0.95;  }
			if(wh > ( $(window).height() * 0.95 ) ) { wh = $(window).height() * 0.95; }

			$('#mediaupload').dialog({
				autoOpen: true,
				width: ww,
				height: wh,
				resizable: false,

				dialogClass: "modalfixed dle-popup-mediaupload",
				classes: {
					"ui-dialog": "modalfixed dle-popup-mediaupload"
				},
				open: function(event, ui) {
					$('.dle-popup-mediaupload').append( $('#mediaupload-buttonpane').html() );
					$('#mediaupload-buttonpane').remove();
				},
				dragStart: function(event, ui) {
					$("#mediaupload").css('visibility', 'hidden');
					$(".modalfixed").fadeTo(0, 0.8);
				},
				dragStop: function(event, ui) {
					$("#mediaupload").css('visibility', 'visible');
					$(".modalfixed").fadeTo(0, 1);
				}
			});

			media_upload_manager = manager;
			$('#mediaupload').dialog( "option", "position", { my: "center", at: "center", of: window } );

		}, 'html');

		return false;
};

var dle_save_delay = false;

