	$(document).on("shown.bs.dropdown", ".btn-group", function () {

	    var $ul = $(this).children(".dropdown-menu");
	    var $button = $(this).children(".dropdown-toggle");
	    var ulOffset = $ul.offset();

	    var spaceUp = (ulOffset.top - $button.height() - $ul.height()) - $(window).scrollTop();

	    var spaceDown = $(window).scrollTop() + $(window).height() - (ulOffset.top + $ul.height());

	    if (spaceDown < 20 && (spaceUp >= 20 || spaceUp > spaceDown)) {
	      $(this).addClass("dropup");
	    }
	    
	}).on("hidden.bs.dropdown", ".btn-group", function() {

	    $(this).removeClass("dropup");
	});
    
    $(document).dialogGlobalHandler({
        open: function(event, ui) {
	    	var v = this;
	    	$(v).parent().css("opacity", 0);
	    	$(v).parent().css("animation", '');

	    	setTimeout(function() {
	    		$(v).parent().css("opacity", 1);
	    		$(v).parent().css("animation", 'fadeIn .15s ease-out');
	    	}, 1);
        },
        close: function(event, ui) {
            $(this).parent().css("animation", '');
        }
    });

